import{_ as a,o as s,c as n,a2 as t}from"./chunks/framework.CKCxdkvf.js";const u=JSON.parse('{"title":"UXS-006 — Moon Map","description":"","frontmatter":{},"headers":[],"relativePath":"uxs/UXS-006.md","filePath":"uxs/UXS-006.md"}'),i={name:"uxs/UXS-006.md"};function o(l,e,r,p,c,d){return s(),n("div",null,[...e[0]||(e[0]=[t(`<h1 id="uxs-006-—-moon-map" tabindex="-1">UXS-006 — Moon Map <a class="header-anchor" href="#uxs-006-—-moon-map" aria-label="Permalink to &quot;UXS-006 — Moon Map&quot;">​</a></h1><blockquote><p>Status · Draft v0.1 Visual fidelity · Verified against prototype (P06_moon-map.html) IA anchor · §surfaces/moon · §topbar-patterns · §shared-tokens Related PRD · PRD-006</p></blockquote><h2 id="why-this-uxs-exists" tabindex="-1">Why this UXS exists <a class="header-anchor" href="#why-this-uxs-exists" aria-label="Permalink to &quot;Why this UXS exists&quot;">​</a></h2><p>The Moon Map has two views (3D sphere and 2D flat map) and a detail panel pattern specific to landing sites. This UXS defines both views, the landing site marker appearance, the nation colour system, and the site detail panel.</p><h2 id="principles" tabindex="-1">Principles <a class="header-anchor" href="#principles" aria-label="Permalink to &quot;Principles&quot;">​</a></h2><ul><li>The 3D sphere rotation is the primary discovery mechanism — rotating to find the far side teaches something</li><li>Landing site markers are visible but not cluttered</li><li>Nation colour distinguishes 5 nations without a legend once learned</li><li>&quot;Still on the surface&quot; callout is the most emotionally impactful element of each panel — it must be prominent</li></ul><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><p>In scope: nav bar, 3D sphere view, 2D flat map view, 3D/2D toggle, landing site markers, detail panel (OVERVIEW, GALLERY tabs), nation colour system. Non-goals: sphere texture detail level, map projection choice. Boundary note: sphere rotation physics belongs in the screen module.</p><h2 id="theme" tabindex="-1">Theme <a class="header-anchor" href="#theme" aria-label="Permalink to &quot;Theme&quot;">​</a></h2><p>Dark only.</p><h2 id="tokens" tabindex="-1">Tokens <a class="header-anchor" href="#tokens" aria-label="Permalink to &quot;Tokens&quot;">​</a></h2><h3 id="inherited-from-ia" tabindex="-1">Inherited from IA <a class="header-anchor" href="#inherited-from-ia" aria-label="Permalink to &quot;Inherited from IA&quot;">​</a></h3><p>All shared tokens.</p><h3 id="defined-here" tabindex="-1">Defined here <a class="header-anchor" href="#defined-here" aria-label="Permalink to &quot;Defined here&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>nation-usa:     #4b9cd3   US sites</span></span>
<span class="line"><span>nation-ussr:    #c07070   Soviet sites</span></span>
<span class="line"><span>nation-china:   #c1440e   Chinese sites</span></span>
<span class="line"><span>nation-india:   #ff9933   Indian sites</span></span>
<span class="line"><span>nation-japan:   #ffffff   Japanese sites</span></span>
<span class="line"><span></span></span>
<span class="line"><span>site-marker-size:  4–6px radius depending on mission significance</span></span>
<span class="line"><span>site-marker-glow:  nation colour, 3× radius</span></span>
<span class="line"><span>site-selected:     nation colour, pulsing ring</span></span>
<span class="line"><span>moon-surface:      Three.js texture from static/textures/moon_1024.jpg</span></span></code></pre></div><h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h2><h3 id="_3d-view" tabindex="-1">3D view <a class="header-anchor" href="#_3d-view" aria-label="Permalink to &quot;3D view&quot;">​</a></h3><p>Full-viewport Three.js sphere. Nav bar overlaid. 3D/2D toggle top-right. Landing site markers as Three.js sprites or projected HTML divs. Detail panel right 314px on site click.</p><h3 id="_2d-flat-map" tabindex="-1">2D flat map <a class="header-anchor" href="#_2d-flat-map" aria-label="Permalink to &quot;2D flat map&quot;">​</a></h3><p>Full-viewport Canvas 2D. Equirectangular projection. Site markers as circles at lat/lon-mapped coordinates. Nation legend bottom-left. Detail panel same as 3D.</p><h3 id="site-detail-panel" tabindex="-1">Site detail panel <a class="header-anchor" href="#site-detail-panel" aria-label="Permalink to &quot;Site detail panel&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌───────────────────────────────────┐</span></span>
<span class="line"><span>│  NATION FLAG/COLOUR · AGENCY      │</span></span>
<span class="line"><span>│  MISSION NAME (Bebas Neue 32px)   │</span></span>
<span class="line"><span>│  Year · Type · Status             │</span></span>
<span class="line"><span>├───────────────────────────────────┤</span></span>
<span class="line"><span>│  OVERVIEW │ GALLERY               │</span></span>
<span class="line"><span>├───────────────────────────────────┤</span></span>
<span class="line"><span>│  [Still on the surface]           │</span></span>
<span class="line"><span>│  nation-colour left border        │</span></span>
<span class="line"><span>│  &quot;Hardware still on the Moon:&quot;    │</span></span>
<span class="line"><span>│  - Descent stage                  │</span></span>
<span class="line"><span>│  - Rover (if applicable)          │</span></span>
<span class="line"><span>├───────────────────────────────────┤</span></span>
<span class="line"><span>│  Editorial description            │</span></span>
<span class="line"><span>│  (Crimson Pro italic)             │</span></span>
<span class="line"><span>│                                   │</span></span>
<span class="line"><span>│  Capability proved:               │</span></span>
<span class="line"><span>│  First [X] — required for Mars    │</span></span>
<span class="line"><span>└───────────────────────────────────┘</span></span></code></pre></div><h2 id="component-states" tabindex="-1">Component states <a class="header-anchor" href="#component-states" aria-label="Permalink to &quot;Component states&quot;">​</a></h2><p><strong>Site marker (default):</strong> small circle, nation colour <strong>Site marker (hovered):</strong> slightly larger, brighter glow <strong>Site marker (selected):</strong> pulsing ring, panel open <strong>&quot;Still on the surface&quot; block:</strong> nation-colour left border, <code>rgba(nation,0.08)</code> background <strong>3D/2D toggle:</strong> same pattern as explore screen (vtab style)</p><h2 id="accessibility" tabindex="-1">Accessibility <a class="header-anchor" href="#accessibility" aria-label="Permalink to &quot;Accessibility&quot;">​</a></h2><p>Canvas/WebGL: <code>aria-label=&quot;Interactive Moon map with 16 landing sites. Use the detail panels for screen reader access.&quot;</code>. Detail panels are HTML — screen reader accessible.</p><h2 id="acceptance-criteria" tabindex="-1">Acceptance criteria <a class="header-anchor" href="#acceptance-criteria" aria-label="Permalink to &quot;Acceptance criteria&quot;">​</a></h2><ul><li>[ ] All 16 landing sites visible in both 3D and 2D views</li><li>[ ] Far-side sites (Chang&#39;e 4) only visible when sphere is rotated</li><li>[ ] Each site colour-coded by nation</li><li>[ ] Detail panel opens on site click</li><li>[ ] &quot;Still on the surface&quot; block present for all missions that left hardware</li><li>[ ] Capability callout present in each panel</li><li>[ ] 3D/2D toggle switches views without losing selected site</li><li>[ ] 2D flat map shows all 16 sites at approximately correct lat/lon positions</li></ul><hr><h2 id="extension-—-gallery-learn-tabs-v0-1-10" tabindex="-1">Extension — GALLERY + LEARN tabs (v0.1.10) <a class="header-anchor" href="#extension-—-gallery-learn-tabs-v0-1-10" aria-label="Permalink to &quot;Extension — GALLERY + LEARN tabs (v0.1.10)&quot;">​</a></h2><p>The detail panel gains a tab system: OVERVIEW (existing content) · GALLERY · LEARN. CSS sourced from the shared <code>src/lib/styles/panel-tabs.css</code> introduced in v0.1.10.</p><h3 id="layout-1" tabindex="-1">Layout <a class="header-anchor" href="#layout-1" aria-label="Permalink to &quot;Layout&quot;">​</a></h3><ul><li>Tabs row sits below the agency-row + name + mission-type header, above the existing landing-data grid.</li><li>GALLERY tab renders only when <code>static/data/moon-site-galleries.json[id] &gt; 0</code>. For sites that share an ID with a flown mission (Apollo 11, Chang&#39;e 5, Luna 9, etc.) the photos are copied from <code>images/missions/&lt;id&gt;/</code> at build time — same content, different surface.</li><li>LEARN tab renders only when the moon-site record has non-empty <code>links[]</code>.</li></ul><h3 id="tokens-extension" tabindex="-1">Tokens (extension) <a class="header-anchor" href="#tokens-extension" aria-label="Permalink to &quot;Tokens (extension)&quot;">​</a></h3><p>Inherits all panel-tab tokens from UXS-004 §Extension. Active tab border: <code>#4466ff</code>. GALLERY thumb hover: <code>rgba(68, 102, 255, 0.6)</code>. LEARN tiers: teal (intro) · blue (core) · gold (deep).</p><h3 id="acceptance-criteria-extension" tabindex="-1">Acceptance criteria (extension) <a class="header-anchor" href="#acceptance-criteria-extension" aria-label="Permalink to &quot;Acceptance criteria (extension)&quot;">​</a></h3><ul><li>[ ] OVERVIEW tab content (data grid + &quot;still on the surface&quot; block + capability callout + fact + credit) unchanged</li><li>[ ] GALLERY tab renders Apollo 11 photos identical to those on /missions for the same mission (no duplicate downloads)</li><li>[ ] LEARN tab renders tiered links from <code>moon-site.links</code></li><li>[ ] No GALLERY/LEARN tab on sites without data</li></ul>`,37)])])}const m=a(i,[["render",o]]);export{u as __pageData,m as default};
